"""Classes for interfacing between PISM and the ``siple`` library.

Provides `PISMLocalVector`, an adapter that implements the
:class:`siple.linalg.linalg_abstract.AbstractVector` interface for
PISM :cpp:class:`Array` types, along with logging and pause utilities.
"""

import PISM
import siple
import petsc4py


class PISMLocalVector(siple.linalg.AbstractVector):

    """``siple`` vector interface for PISM :cpp:class:`Array` types.

    Implements :class:`siple.linalg.linalg_abstract.AbstractVector` for
    PISM ``array::Scalar`` and ``array::Vector``.

    Parameters
    ----------
    u : PISM.Scalar or PISM.Vector
        The PISM array to wrap.

    Raises
    ------
    ValueError
        If *u* is not a ``PISM.Scalar`` or ``PISM.Vector``.
    """

    def __init__(self, u):
        if isinstance(u, PISM.Scalar):
            self._core = u
            self.dof = 1
        elif isinstance(u, PISM.Vector):
            self._core = u
            self.dof = 2
        else:
            raise ValueError("A PISMLocalVector wraps PISM array::Scalar or Vector: found a %s" % u)
        self.grid = u.grid()

    def set(self, rhs):
        """Copy values from *rhs* into this vector.

        Parameters
        ----------
        rhs : PISMLocalVector
            Source vector to copy from.
        """
        self._core.copy_from(rhs._core)

    def acc(self, rhs):
        """Add *rhs* to this vector in place (``self += rhs``).

        Parameters
        ----------
        rhs : PISMLocalVector
            Vector to add.
        """
        self._core.add(1., rhs._core)

    def scale(self, t):
        """Scale this vector in place by scalar *t*.

        Parameters
        ----------
        t : float
            Scale factor.
        """
        self._core.scale(t)

    def axpy(self, t, v):
        """Perform ``self += t * v`` in place.

        Parameters
        ----------
        t : float
            Scale factor.
        v : PISMLocalVector
            Vector to add.
        """
        self._core.add(t, v._core)

    def copy(self):
        """Return a deep copy of this vector.

        Returns
        -------
        PISMLocalVector
            A new vector with the same values.
        """
        c = self.vector_like()
        c._core.copy_from(self._core)
        return c

    def vector_like(self):
        """Return a new uninitialized vector with the same shape and type.

        Returns
        -------
        PISMLocalVector
            A new vector of the same kind and grid.
        """
        if self.dof == 1:
            c = PISM.Scalar2(self.grid, "")
        else:
            c = PISM.Vector2(self.grid, "")
        return PISMLocalVector(c)

    def zero_like(self):
        """Return a new zero-filled vector with the same shape and type.

        Returns
        -------
        PISMLocalVector
            A new vector initialized to zero.
        """
        z = self.vector_like()
        z._core.set(0.)
        return z

    def dim(self):
        """Return the total number of degrees of freedom.

        Returns
        -------
        int
            ``dof * Mx * My``.
        """
        grid = self._core.grid()
        return self.dof * grid.Mx() * grid.My()

    def core(self):
        """Return the underlying PISM array.

        Returns
        -------
        PISM.Scalar or PISM.Vector
            The wrapped PISM array object.
        """
        return self._core

    def norm(self, name):
        """Compute a norm of this vector.

        Parameters
        ----------
        name : {'linf', 'l2', 'l1'}
            The type of norm to compute.

        Returns
        -------
        float
            The computed norm value.

        Raises
        ------
        ValueError
            If *name* is not a recognized norm type.
        """
        if name == 'linf':
            return self._core.norm(petsc4py.PETSc.NormType.NORM_INFINITY)
        if name == 'l2':
            return self._core.norm(petsc4py.PETSc.NormType.NORM_2)
        if name == 'l1':
            return self._core.norm(petsc4py.PETSc.NormType.NORM_1)

        raise ValueError()


def pism_logger(message, severity):
    """Log a message using PISM's logging facility.

    Implements a ``siple`` logger callback that forwards messages to the
    terminal via :func:`PISM.logging.log`.

    Parameters
    ----------
    message : str
        The message to log.
    severity : int
        Verbosity level passed to :func:`PISM.logging.log`.
    """
    verbosity = severity
    PISM.logging.log(message + '\n', verbosity)


def pism_pause(message_in=None, message_out=None):
    """Pause execution, suitable for parallel ``siple`` runs.

    If *stdin* is a TTY, delegates to :func:`siple.reporting.std_pause`.
    Otherwise reads a single character from *stdin* and prints the
    optional messages.

    Parameters
    ----------
    message_in : str or None, optional
        Message to display before waiting for input.
    message_out : str or None, optional
        Message to display after input is received.
    """
    import sys
    import os
    fd = sys.stdin.fileno()
    com = PISM.Context().com
    if os.isatty(fd):
        return siple.reporting.std_pause(message_in, message_out)
    if not message_in is None:
        PISM.verbPrintf(1, com, message_in + "\n")
    _ = sys.stdin.read(1)
    if not message_out is None:
        PISM.verbPrintf(1, com, message_out + "\n")
